// Script per generare un modulo che accetta e salva il testo inserito dall'utente
document.addEventListener("DOMContentLoaded", function () {
  const form = document.createElement("form");
  form.setAttribute("method", "post");
  form.setAttribute("action", "/save-text");

  const textarea = document.createElement("textarea");
  textarea.setAttribute("name", "userText");
  textarea.setAttribute("placeholder", "Inserisci il testo qui...");
  textarea.setAttribute("rows", "10");
  textarea.setAttribute("cols", "50");

  const submitButton = document.createElement("button");
  submitButton.setAttribute("type", "submit");
  submitButton.textContent = "Salva Testo";

  form.appendChild(textarea);
  form.appendChild(submitButton);

  document.body.appendChild(form);
});
